def retry(func, attempts, fallback):
    for i in range(attempts):
        try:
            return func()
        except Exception:
            continue
    return fallback

calls = {"n": 0}
def flaky():
    calls["n"] += 1
    if calls["n"] < 3:
        raise ConnectionError("blip")
    return "ok"

print(retry(flaky, 5, "cached"))
